class c{ws=null;serverUrl;wsUrl;onProgress=null;onModelReady=null;reconnectTimer=null;connected=!1;constructor(e="http://localhost:3001"){this.serverUrl=e,this.wsUrl=e.replace("http","ws")+"/ws"}connect(){return new Promise(async(e,s)=>{try{let t=this.wsUrl;try{const o=await fetch(`${this.serverUrl}/api/auth/token`,{method:"POST"});if(o.ok){const{token:n}=await o.json();t=`${this.wsUrl}?token=${n}`}}catch{console.warn("[API] Token fetch failed, connecting without token")}this.ws=new WebSocket(t),this.ws.binaryType="arraybuffer",this.ws.onopen=()=>{this.connected=!0,console.log("[API] WebSocket connected"),e()},this.ws.onmessage=o=>{if(o.data instanceof ArrayBuffer)console.log(`[API] Received binary model: ${o.data.byteLength} bytes`),this.onModelReady?.(o.data);else{const n=JSON.parse(o.data);this.handleMessage(n)}},this.ws.onclose=()=>{this.connected=!1,console.log("[API] WebSocket disconnected"),this.scheduleReconnect()},this.ws.onerror=()=>{this.connected=!1,s(new Error("WebSocket connection failed"))}}catch(t){s(t)}})}disconnect(){this.reconnectTimer&&clearTimeout(this.reconnectTimer),this.ws?.close(),this.ws=null,this.connected=!1}isConnected(){return this.connected}scheduleReconnect(){this.reconnectTimer||(this.reconnectTimer=window.setTimeout(()=>{this.reconnectTimer=null,console.log("[API] Attempting reconnect..."),this.connect().catch(()=>{this.scheduleReconnect()})},3e3))}handleMessage(e){switch(e.type){case"connected":console.log(`[API] Server assigned ID: ${e.clientId}`);break;case"model-progress":case"job-progress":this.onProgress?.(e.progress,e.stage);break;case"model-ready":console.log(`[API] Model ready: ${e.modelId}, ${e.size} bytes`);break;case"job-started":console.log(`[API] Job started: ${e.jobId}`),this.onProgress?.(0,"处理中...");break;case"job-complete":console.log(`[API] Job complete: ${e.jobId}`),this.onProgress?.(1,"完成"),e.modelUrl&&this.downloadModel(e.modelUrl);break;case"pong":break;default:console.log("[API] Unknown message:",e)}}async uploadPhoto(e){const s=new FormData;s.append("photo",e,"capture.jpg");const t=await fetch(`${this.serverUrl}/api/upload`,{method:"POST",body:s});if(!t.ok)throw new Error(`Upload failed: ${t.status}`);return t.json()}async downloadModel(e){const s=e.startsWith("http")?e:`${this.serverUrl}${e}`,t=await fetch(s);if(!t.ok)throw new Error(`Download failed: ${t.status}`);const o=await t.arrayBuffer();return this.onModelReady?.(o),o}async getModels(){return(await(await fetch(`${this.serverUrl}/api/models`)).json()).models}async checkHealth(){try{return(await fetch(`${this.serverUrl}/api/health`,{signal:AbortSignal.timeout(3e3)})).ok}catch{return!1}}requestModel(e="demo-face"){if(!this.ws||this.ws.readyState!==WebSocket.OPEN){console.warn("[API] WebSocket not connected");return}this.ws.send(JSON.stringify({type:"request-model",modelId:e}))}setOnProgress(e){this.onProgress=e}setOnModelReady(e){this.onModelReady=e}}export{c as APIClient};
